<?php
namespace App\Http\Controllers\Api\Marketing;
use App\Http\Controllers\Concerns\ApiResponses; use App\Http\Controllers\Controller; use Illuminate\Http\JsonResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB;
class WhatsappOptInController extends Controller { use ApiResponses; public function optIn(Request $r): JsonResponse { $d=$r->validate(['phone'=>'required|string|max:60','source'=>'nullable|string|max:80']); DB::table('whatsapp_opt_ins')->updateOrInsert(['phone'=>$d['phone']],['opted_in'=>true,'source'=>$d['source']??'api','opted_in_at'=>now(),'updated_at'=>now(),'created_at'=>now()]); return $this->success(['message'=>'Opt-in recorded.']); } public function optOut(Request $r): JsonResponse { $d=$r->validate(['phone'=>'required|string|max:60']); DB::table('whatsapp_opt_ins')->updateOrInsert(['phone'=>$d['phone']],['opted_in'=>false,'opted_out_at'=>now(),'updated_at'=>now(),'created_at'=>now()]); DB::table('suppression_lists')->insert(['channel'=>'whatsapp','phone'=>$d['phone'],'reason'=>'whatsapp_opt_out','suppressed_at'=>now(),'created_at'=>now(),'updated_at'=>now()]); return $this->success(['message'=>'Opt-out recorded.']); } }
